// hooks/useAnalytics.js
import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import ReactGA from 'react-ga4';

const useAnalytics = () => {
  const location = useLocation();

  // Track page views automatiquement
  useEffect(() => {
    ReactGA.send({ hitType: 'pageview', page: location.pathname + location.search });
  }, [location]);

  const trackAddToCart = (product, quantity = 1) => {
    ReactGA.event('add_to_cart', {
      product_id: product.id,
      product_name: product.name,
      price: product.price,
      quantity,
      currency: 'XAF'
    });
  };

  const trackBeginCheckout = (cartItems, total) => {
    ReactGA.event('begin_checkout', {
      items: cartItems.map(i => ({ id: i.id, name: i.name, price: i.price, quantity: i.quantity })),
      value: total,
      currency: 'XAF'
    });
  };

  const trackPurchase = (orderId, total, items) => {
    ReactGA.event('purchase', {
      transaction_id: orderId,
      value: total,
      currency: 'XAF',
      items: items.map(i => ({ id: i.id, name: i.name, price: i.price, quantity: i.quantity }))
    });
  };

  return { trackAddToCart, trackBeginCheckout, trackPurchase };
};

export default useAnalytics;
